import time
import math
import random

def solve(cities):
    t0 = time.time()
    n = len(cities)
    budget = 0.04 * n

    def dist(i, j):
        dx = cities[i][0] - cities[j][0]
        dy = cities[i][1] - cities[j][1]
        return int(math.sqrt(dx*dx + dy*dy) + 0.5)

    # Precompute distance matrix for small n
    if n <= 400:
        D = [[0]*n for _ in range(n)]
        for i in range(n):
            for j in range(i+1, n):
                d = int(math.sqrt((cities[i][0]-cities[j][0])**2 + (cities[i][1]-cities[j][1])**2) + 0.5)
                D[i][j] = d
                D[j][i] = d
        def d(i, j): return D[i][j]
    else:
        def d(i, j):
            dx = cities[i][0] - cities[j][0]
            dy = cities[i][1] - cities[j][1]
            return int(math.sqrt(dx*dx + dy*dy) + 0.5)

    K = min(20, n - 1)
    neighbors = []
    for i in range(n):
        row = sorted(range(n), key=lambda j: d(i,j) if j != i else float('inf'))
        neighbors.append(row[:K])

    def tour_length(tour):
        return sum(d(tour[i], tour[(i+1)%n]) for i in range(n))

    def nn_tour(start):
        visited = [False]*n
        tour = [start]
        visited[start] = True
        for _ in range(n-1):
            cur = tour[-1]
            best_d, best_j = float('inf'), -1
            for j in neighbors[cur]:
                if not visited[j]:
                    dd = d(cur, j)
                    if dd < best_d:
                        best_d, best_j = dd, j
            if best_j == -1:
                for j in range(n):
                    if not visited[j]:
                        dd = d(cur, j)
                        if dd < best_d:
                            best_d, best_j = dd, j
            tour.append(best_j)
            visited[best_j] = True
        return tour

    # Build initial tour
    best_tour = None
    best_len = float('inf')
    starts = random.sample(range(n), min(5, n))
    for s in starts:
        if time.time() - t0 > budget * 0.25:
            break
        t = nn_tour(s)
        l = tour_length(t)
        if l < best_len:
            best_len, best_tour = l, t[:]

    def two_opt_pass(tour, pos, time_limit):
        improved = True
        dont_look = [False]*n
        tl = tour_length(tour)
        while improved:
            improved = False
            for idx in range(n):
                if time.time() - t0 > time_limit:
                    return tour, pos, tl, False
                ci = tour[idx]
                if dont_look[ci]:
                    continue
                i = idx
                i1 = (i+1)%n
                ci1 = tour[i1]
                d_ci_ci1 = d(ci, ci1)
                found = False
                for cj in neighbors[ci]:
                    if d(ci, cj) >= d_ci_ci1:
                        break
                    j = pos[cj]
                    if j == i or j == i1:
                        continue
                    cj1 = tour[(j+1)%n]
                    if cj == ci1:
                        continue
                    gain = d_ci_ci1 + d(cj, cj1) - d(ci, cj) - d(ci1, cj1)
                    if gain > 0:
                        a, b = i1, j
                        if a <= b:
                            tour[a:b+1] = tour[a:b+1][::-1]
                        else:
                            seg = (tour[a:] + tour[:b+1])[::-1]
                            tour[a:] = seg[:n-a]
                            tour[:b+1] = seg[n-a:]
                        for k in range(n):
                            pos[tour[k]] = k
                        tl -= gain
                        improved = True
                        found = True
                        dont_look[ci] = False
                        dont_look[cj] = False
                        break
                if not found:
                    dont_look[ci] = True
        return tour, pos, tl, True

    def or_opt_pass(tour, pos, tl, time_limit):
        improved = True
        while improved:
            improved = False
            for seg_len in [1, 2, 3]:
                for i in range(n):
                    if time.time() - t0 > time_limit:
                        return tour, pos, tl, False
                    prev_i = (i-1)%n
                    i_end = (i+seg_len-1)%n
                    i_next = (i+seg_len)%n
                    before = tour[prev_i]
                    seg_s = tour[i]
                    seg_e = tour[i_end]
                    after = tour[i_next]
                    if before == seg_s or after == seg_e or before == seg_e or after == seg_s:
                        continue
                    remove_gain = d(before, seg_s) + d(seg_e, after) - d(before, after)
                    if remove_gain <= 0:
                        continue
                    seg = [tour[(i+k)%n] for k in range(seg_len)]
                    for cj in neighbors[seg_s]:
                        j = pos[cj]
                        in_seg = any((i+k)%n == j for k in range(seg_len))
                        if in_seg or j == prev_i:
                            continue
                        cj1 = tour[(j+1)%n]
                        if cj1 == seg_s:
                            continue
                        insert_cost = d(cj, seg_s) + d(seg_e, cj1) - d(cj, cj1)
                        if remove_gain - insert_cost > 0:
                            skip = set((i+k)%n for k in range(seg_len))
                            new_tour = [tour[k] for k in range(n) if k not in skip]
                            ins = new_tour.index(cj)
                            new_tour = new_tour[:ins+1] + seg + new_tour[ins+1:]
                            tour = new_tour
                            for k in range(n):
                                pos[tour[k]] = k
                            tl = tl - remove_gain + insert_cost
                            improved = True
                            break
        return tour, pos, tl, True

    def double_bridge(tour):
        # 4 random cut points
        positions = sorted(random.sample(range(1, n), 4))
        a, b, c, d_ = positions
        seg1 = tour[:a]
        seg2 = tour[a:b]
        seg3 = tour[b:c]
        seg4 = tour[c:d_]
        seg5 = tour[d_:]
        # AB CD -> AC BD (one of several patterns)
        new_tour = seg1 + seg3 + seg2 + seg4 + seg5
        return new_tour

    def full_optimize(tour, time_limit):
        pos = [0]*n
        for i, c in enumerate(tour):
            pos[c] = i
        tl = tour_length(tour)
        tour, pos, tl, _ = two_opt_pass(tour, pos, tl * 0 + tl, time_limit * 0.6 + t0 * 0)
        # recompute properly
        if time.time() - t0 < time_limit:
            tour, pos, tl, _ = or_opt_pass(tour, pos, tl, time_limit)
        if time.time() - t0 < time_limit:
            tour, pos, tl, _ = two_opt_pass(tour, pos, tl, time_limit)
        return tour, tl

    # Initial optimization
    phase1_end = t0 + budget * 0.5
    tour = best_tour[:]
    pos = [0]*n
    for i, c in enumerate(tour):
        pos[c] = i
    tl = best_len

    tour, pos, tl, _ = two_opt_pass(tour, pos, tl, phase1_end)
    if time.time() - t0 < phase1_end:
        tour, pos, tl, _ = or_opt_pass(tour, pos, tl, phase1_end)
    if time.time() - t0 < phase1_end:
        tour, pos, tl, _ = two_opt_pass(tour, pos, tl, phase1_end)

    best_tour = tour[:]
    best_len = tl

    # ILS with double-bridge
    while time.time() - t0 < budget * 0.95:
        if time.time() - t0 > budget * 0.93:
            break
        remaining = budget * 0.95 - (time.time() - t0)
        if remaining < budget * 0.05:
            break
        # Perturb
        new_tour = double_bridge(best_tour[:])
        pos2 = [0]*n
        for i, c in enumerate(new_tour):
            pos2[c] = i
        tl2 = tour_length(new_tour)
        iter_budget = min(remaining * 0.4, budget * 0.15)
        iter_end = time.time() + iter_budget
        new_tour, pos2, tl2, _ = two_opt_pass(new_tour, pos2, tl2, iter_end)
        if time.time() < iter_end:
            new_tour, pos2, tl2, _ = or_opt_pass(new_tour, pos2, tl2, iter_end)
        if time.time() < iter_end:
            new_tour, pos2, tl2, _ = two_opt_pass(new_tour, pos2, tl2, iter_end)
        if tl2 < best_len:
            best_len = tl2
            best_tour = new_tour[:]

    return best_tour
